// ── Low-level fetch helpers ────────────────────────────────────────
async function sbGet(table, filters='') {
  try {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?${filters}`, {
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });
    if (!res.ok) return null;
    return await res.json();
  } catch(e) { return null; }
}

async function sbUpsert(table, data) {
  try {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'resolution=merge-duplicates,return=minimal'
      },
      body: JSON.stringify(data)
    });
    return res.ok;
  } catch(e) { return false; }
}

async function sbDelete(table, filter) {
  try {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?${filter}`, {
      method: 'DELETE',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });
    return res.ok;
  } catch(e) { return false; }
}

// ── Cloud save/load for daily records ─────────────────────────────
window.cloudSaveRecords = async function() {
  setSyncStatus(' saving...');
  // Save all records as a single JSON blob keyed by property
  const ok = await sbUpsert('ri_data', {
    property_id: PROPERTY_ID,
    key: 'records',
    value: JSON.stringify(records),
    updated_at: new Date().toISOString()
  });
  setSyncStatus(ok ? ' synced' : '⚠ local only');
  return ok;
};

window.cloudLoadRecords = async function() {
  setSyncStatus(' loading...');
  const data = await sbGet('ri_data', `property_id=eq.${PROPERTY_ID}&key=eq.records&select=value,updated_at`);
  if (data && data.length > 0) {
    try {
      const cloudRecords = JSON.parse(data[0].value);
      if (cloudRecords && cloudRecords.length > 0) {
        records = cloudRecords;
        saveRecords(); // also save to localStorage as backup
        setSyncStatus(` ${records.length} records`);
        return true;
      }
    } catch(e) {}
  }
  setSyncStatus('local only');
  return false;
};

// ── Cloud save/load for settings (budgets, costs, menu, seats) ────
window.cloudSaveSettings = async function() {
  const settings = {
    budgets: localStorage.getItem('ri_budgets_v1') || '{}',
    costs:   localStorage.getItem('ri_costs_v1')   || '{}',
    menu:    localStorage.getItem('ri_menu_v1')    || '[]',
    seats:   localStorage.getItem('ri_seats_v1')   || '80',
  };
  return await sbUpsert('ri_data', {
    property_id: PROPERTY_ID,
    key: 'settings',
    value: JSON.stringify(settings),
    updated_at: new Date().toISOString()
  });
};

// Dedicated save/load for sales data (stored separately due to size)
window.cloudSaveSales = async function() {
  const salesData = localStorage.getItem('ri_sales_data_v1');
  if (!salesData || salesData === 'null') return false;
  setSyncStatus('syncing sales...');
  try {
    const res = await fetch(SUPABASE_URL + '/rest/v1/ri_data', {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Content-Type': 'application/json',
        'Prefer': 'resolution=merge-duplicates,return=minimal'
      },
      body: JSON.stringify({
        property_id: PROPERTY_ID,
        key: 'sales_data',
        value: salesData,
        updated_at: new Date().toISOString()
      })
    });
    if (res.ok) {
      setSyncStatus(records.length + ' records · sales synced');
      return true;
    } else {
      const err = await res.text();
      console.error('[cloudSaveSales] Supabase error:', res.status, err);
      setSyncStatus('sales sync failed');
      return false;
    }
  } catch(e) {
    console.error('[cloudSaveSales] Network error:', e);
    setSyncStatus('sales sync error');
    return false;
  }
};

window.cloudLoadSales = async function() {
  try {
    const data = await sbGet('ri_data', 'property_id=eq.' + PROPERTY_ID + '&key=eq.sales_data&select=value');
    if (!data || !data.length || !data[0].value) return false;

    const cloudSD = JSON.parse(data[0].value);
    const cloudItems = cloudSD && cloudSD.by_item ? Object.keys(cloudSD.by_item).length : 0;
    console.log('[cloudLoadSales] Cloud items:', cloudItems);
    if (cloudItems === 0) return false;

    // Count local items
    const localItems = window.SALES_DATA_LIVE && window.SALES_DATA_LIVE.by_item
      ? Object.keys(window.SALES_DATA_LIVE.by_item).length : 0;

    // Only load from cloud if local is empty OR cloud has more data
    if (localItems === 0 || cloudItems > localItems) {
      localStorage.setItem('ri_sales_data_v1', data[0].value);
      window.SALES_DATA_LIVE = cloudSD;
      console.log('[cloudLoadSales] Loaded from cloud ✅ (' + cloudItems + ' items)');
      return true;
    }
    console.log('[cloudLoadSales] Local data kept (local=' + localItems + ' cloud=' + cloudItems + ')');
    return false;
  } catch(e) {
    console.error('[cloudLoadSales] Error:', e);
    return false;
  }
};

window.cloudLoadSettings = async function() {
  const data = await sbGet('ri_data', `property_id=eq.${PROPERTY_ID}&key=eq.settings&select=value`);
  if (data && data.length > 0) {
    try {
      const s = JSON.parse(data[0].value);
      if (s.budgets) localStorage.setItem('ri_budgets_v1', s.budgets);
      if (s.costs)   localStorage.setItem('ri_costs_v1',   s.costs);
      if (s.menu)    localStorage.setItem('ri_menu_v1',    s.menu);
      if (s.seats)   localStorage.setItem('ri_seats_v1',   s.seats);
      return true;
    } catch(e) {}
  }
  return false;
};

// ── Master init: load from cloud on startup ────────────────────────
window.cloudInit = async function() {
  setSyncStatus(' connecting...');
  const recordsLoaded = await window.cloudLoadRecords();
  await window.cloudLoadSettings();
  const salesLoaded   = await window.cloudLoadSales();
  const hourlyLoaded  = await window.cloudLoadHourly?.();

  if (recordsLoaded || salesLoaded || hourlyLoaded) {
    renderPage(currentTab);
    if (currentTab === 'sales')  renderSales();
    if (currentTab === 'hourly') renderHourly();
    toast('Cloud data loaded', 'success');
  } else {
    setSyncStatus('local only');
  }
};

