            style="flex:1;background:rgba(255,255,255,.05);border:1px solid rgba(124,92,252,.3);border-radius:10px;padding:10px 14px;color:#fff;font-size:13px;font-family:inherit;resize:none;min-height:44px;max-height:120px;line-height:1.5;outline:none"
            rows="1"
            onkeydown="if(event.key==='Enter'&&!event.shiftKey){event.preventDefault();aiSendFromInput()}"
