function renderRepDiscounts(R) {
  const MONTHS_L = ['January','February','March','April','May','June','July',
                    'August','September','October','November','December'];
  const MONTHS_S = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const dc = R.disc_comp;

  $('rep-content').innerHTML = `
    <!-- Year totals KPI cards -->
    <div class="grid4" style="margin-bottom:12px">
      ${[2024,2025,2026].map(yr=>{
        const d=dc?.[yr]||{}; if(!d.net) return '';
        return `<div class="card" style="border-top-color:${yr===2024?'#f5c842':yr===2025?'#00d4aa':'#ff6b35'}">
          <div class="ct">${yr} DISC + COMP</div>
          <div style="font-size:22px;font-weight:900;color:${yr===2024?'#f5c842':yr===2025?'#00d4aa':'#ff6b35'};font-family:monospace">${fmt(d.disc+d.comp)}</div>
          <div style="font-size:12px;color:#888;margin-top:4px">
            Disc: <span style="color:#ff4466">${fmt(d.disc)}</span>
            <span style="color:#555;margin:0 4px">·</span>
            <span style="color:#ff446688">${d.disc_pct}% of net</span>
          </div>
          <div style="font-size:12px;color:#888;margin-top:2px">
            Comp: <span style="color:#ff9f43">${fmt(d.comp)}</span>
            <span style="color:#555;margin:0 4px">·</span>
            <span style="color:#ff9f4388">${d.comp_pct}% of net</span>
          </div>
        </div>`;
      }).join('')}
    </div>

    <!-- Line charts -->
    <div class="grid2e" style="margin-bottom:12px">
      <div class="card"><div class="ct">Discounts by Month — All Years</div>
        <div style="position:relative;height:220px"><canvas id="ch-disc-monthly"></canvas></div></div>
      <div class="card"><div class="ct">Complimentary by Month — All Years</div>
        <div style="position:relative;height:220px"><canvas id="ch-comp-monthly"></canvas></div></div>
    </div>

    <!-- Monthly detail table with % -->
    <div class="card" style="margin-bottom:12px">
      <div class="ct">Monthly Discounts + Complimentary Detail</div>
      <div class="tbl-wrap">
        <table style="width:100%;border-collapse:collapse">
          <thead><tr>
            ${['Month',
               '2024 Net','2024 Disc','Disc %','2024 Comp','Comp %',
               '2025 Net','2025 Disc','Disc %','2025 Comp','Comp %',
               '2026 Net','2026 Disc','Disc %','2026 Comp','Comp %'].map(h=>
              `<th style="padding:6px 8px;font-family:monospace;font-size:9px;color:#555;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.07);background:#16161f">${h}</th>`
            ).join('')}
          </tr></thead>
          <tbody>
            ${MONTHS_L.map((m,i)=>{
              const d24=dc?.[2024]?.monthly?.[m]||{}, d25=dc?.[2025]?.monthly?.[m]||{}, d26=dc?.[2026]?.monthly?.[m]||{};
              if(!d24.net&&!d25.net&&!d26.net) return '';
              const cell=(n,d,c,dp,cp)=>!n?'<td colspan="5" style="color:#333;text-align:center;padding:6px 8px">—</td>':
                `<td class="mono" style="padding:6px 8px;color:#888;font-size:11px">${fmt(n)}</td>
                 <td class="mono" style="padding:6px 8px;color:#ff4466;font-size:11px">${fmt(d)}</td>
                 <td class="mono" style="padding:6px 8px;color:#ff446688;font-size:10px">${dp}%</td>
                 <td class="mono" style="padding:6px 8px;color:#ff9f43;font-size:11px">${fmt(c)}</td>
                 <td class="mono" style="padding:6px 8px;color:#ff9f4388;font-size:10px">${cp}%</td>`;
              return `<tr style="border-bottom:1px solid rgba(255,255,255,.03)">
                <td style="padding:6px 8px;font-weight:700;font-size:12px">${MONTHS_S[i]}</td>
                ${cell(d24.net,d24.disc,d24.comp,d24.disc_pct,d24.comp_pct)}
                ${cell(d25.net,d25.disc,d25.comp,d25.disc_pct,d25.comp_pct)}
                ${cell(d26.net,d26.disc,d26.comp,d26.disc_pct,d26.comp_pct)}
              </tr>`;
            }).join('')}
            <tr style="border-top:2px solid rgba(255,255,255,.1);font-weight:700">
              <td style="padding:6px 8px">TOTAL</td>
              ${[2024,2025,2026].map(yr=>{
                const d=dc?.[yr]||{};
                return `<td class="mono" style="padding:6px 8px;color:#888;font-size:11px">${fmt(d.net||0)}</td>
                        <td class="mono" style="padding:6px 8px;color:#ff4466;font-size:11px">${fmt(d.disc||0)}</td>
                        <td class="mono" style="padding:6px 8px;color:#ff446688;font-size:10px">${d.disc_pct||0}%</td>
                        <td class="mono" style="padding:6px 8px;color:#ff9f43;font-size:11px">${fmt(d.comp||0)}</td>
                        <td class="mono" style="padding:6px 8px;color:#ff9f4388;font-size:10px">${d.comp_pct||0}%</td>`;
              }).join('')}
            </tr>
          </tbody>
        </table>
      </div>
    </div>`;

  // Line charts
  mkLine('ch-disc-monthly', MONTHS_S, [
    {label:'2024',data:MONTHS_L.map(m=>dc?.[2024]?.monthly?.[m]?.disc||null),borderColor:'#f5c842',backgroundColor:'#f5c84222'},
    {label:'2025',data:MONTHS_L.map(m=>dc?.[2025]?.monthly?.[m]?.disc||null),borderColor:'#00d4aa',backgroundColor:'#00d4aa22'},
    {label:'2026',data:MONTHS_L.map(m=>dc?.[2026]?.monthly?.[m]?.disc||null),borderColor:'#ff6b35',backgroundColor:'#ff6b3522'},
  ]);
  mkLine('ch-comp-monthly', MONTHS_S, [
    {label:'2024',data:MONTHS_L.map(m=>dc?.[2024]?.monthly?.[m]?.comp||null),borderColor:'#f5c842',backgroundColor:'#f5c84222'},
    {label:'2025',data:MONTHS_L.map(m=>dc?.[2025]?.monthly?.[m]?.comp||null),borderColor:'#00d4aa',backgroundColor:'#00d4aa22'},
    {label:'2026',data:MONTHS_L.map(m=>dc?.[2026]?.monthly?.[m]?.comp||null),borderColor:'#ff6b35',backgroundColor:'#ff6b3522'},
  ]);
}



function renderHotelBreakfast() {
  // Merge static Excel hotel data with manually added records
  const excelHd = EXCEL_DATA.hotel_daily || [];

  // Build a set of dates already in excel data
  const excelDates = new Set(excelHd.map(r => r.date));

  // Get manual records that have hotel breakfast data
  const manualHd = records
    .filter(r => r.source === 'manual' && (r.hotel_bfast_gross || r.hotel_bfast_net) && !excelDates.has(r.date))
    .map(r => ({
      date:    r.date,
      year:    r.year,
      month:   r.month ? (r.month.charAt(0).toUpperCase() + r.month.slice(1).toLowerCase()) : '',
      gross:   r.hotel_bfast_gross || 0,
      net:     r.hotel_bfast_net   || 0,
      covers:  r.hotel_bfast_covers || r.ppl_bfast || 0,
      avg:     (r.hotel_bfast_covers||r.ppl_bfast) ? (r.hotel_bfast_net||(r.hotel_bfast_gross*0.86)) / (r.hotel_bfast_covers||r.ppl_bfast) : 0,
    }));

  // Also update existing excel records if a manual entry exists for same date
  const manualUpdates = records
    .filter(r => r.source === 'manual' && (r.hotel_bfast_gross || r.hotel_bfast_net) && excelDates.has(r.date))
    .reduce((acc, r) => { acc[r.date] = r; return acc; }, {});

  const hd = [
    ...excelHd.map(r => {
      const upd = manualUpdates[r.date];
      if (!upd) return r;
      return {
        ...r,
        gross:   (r.gross   || 0) + (upd.hotel_bfast_gross || 0),
        net:     (r.net     || 0) + (upd.hotel_bfast_net   || 0),
        covers:  (r.covers  || 0) + (upd.hotel_bfast_covers || upd.ppl_bfast || 0),
      };
    }),
    ...manualHd,
  ].sort((a, b) => a.date.localeCompare(b.date));
  const MONTHS_L=['January','February','March','April','May','June','July','August','September','October','November','December'];
  const MONTHS_S=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const monthMap={'JAN':'January','FEB':'February','MAR':'March','APR':'April','MAY':'May','JUN':'June','JUL':'July','AUG':'August','SEP':'September','OCT':'October','NOV':'November','DEC':'December'};

  // Apply BOTH year and month filters from the global filter state
  const selYear = yearFilter === 'ALL' ? null : parseInt(yearFilter);
  const selMonthFull = monthFilter === 'ALL' ? null : (monthMap[monthFilter] || MONTHS_L.find(m=>m.toUpperCase().startsWith(monthFilter.slice(0,3))));
  const d = hd.filter(r=>(!selYear||r.year===selYear)&&(!selMonthFull||r.month===selMonthFull));

  const tG = d.reduce((a,r)=>a+r.gross,0);
  const tN = d.reduce((a,r)=>a+r.net,0);
  const tC = d.reduce((a,r)=>a+r.covers,0);
  const asp = tC ? tN/tC : 0;
  // Charts use year filter only (show monthly breakdown)
  const hdYear = selYear ? hd.filter(r=>r.year===selYear) : hd;
  const yrs = selYear ? [selYear] : [...new Set(hd.map(r=>r.year))].sort();

  $('hb-page-kpis').innerHTML = [
    kpiHtml('Total Gross',fmt(tG),'#f5c842',(selYear||'All years')+(selMonthFull?' · '+selMonthFull.slice(0,3):'')+' · '+d.length+' days'),
    kpiHtml('Total Net',fmt(tN),'#f5c842',tG?((tN/tG)*100).toFixed(1)+'% margin':'—'),
    kpiHtml('Total Covers',fmtN(tC),'#7c5cfc',Math.round(tC/(d.length||1))+' avg/day'),
    kpiHtml('Avg / Cover',fmt(asp),'#00d4aa','net per hotel guest'),
  ].join('');

  // Monthly chart
  mkChart('ch-hb-monthly',{
    type:'bar',
    data:{
      labels:MONTHS_S,
      datasets:yrs.map(y=>({
        label:String(y),
        data:MONTHS_L.map(m=>{
          const r=hdYear.filter(x=>x.year==y&&x.month===m);
          return r.length?r.reduce((a,x)=>a+x.gross,0):null;
        }),
        backgroundColor:YEAR_COLORS[y]+'cc',borderRadius:4,borderSkipped:false,
      }))
    },
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10,padding:10}}},
      scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555',callback:v=>'€'+Math.round(v/1000)+'k'}}}}
  });

  // Covers by year
  mkChart('ch-hb-covers',{
    type:'line',
    data:{
      labels:MONTHS_S,
      datasets:yrs.map(y=>({
        label:String(y),
        data:MONTHS_L.map(m=>{
          const r=hdYear.filter(x=>x.year==y&&x.month===m);
          return r.length?r.reduce((a,x)=>a+x.covers,0):null;
        }),
        borderColor:YEAR_COLORS[y],backgroundColor:YEAR_COLORS[y]+'22',
        borderWidth:2,pointRadius:4,tension:.3,fill:false,
      }))
    },
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10,padding:10}}},
      scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555'}}}}
  });

  // Avg/cover by year
  mkChart('ch-hb-avg',{
    type:'line',
    data:{
      labels:MONTHS_S,
      datasets:yrs.map(y=>({
        label:String(y),
        data:MONTHS_L.map(m=>{
          const r=hdYear.filter(x=>x.year==y&&x.month===m);
          if(!r.length) return null;
          const tNm=r.reduce((a,x)=>a+x.net,0), tCm=r.reduce((a,x)=>a+x.covers,0);
          return tCm?+(tNm/tCm).toFixed(2):null;
        }),
        borderColor:YEAR_COLORS[y],backgroundColor:YEAR_COLORS[y]+'22',
        borderWidth:2,pointRadius:4,tension:.3,fill:false,
      }))
    },
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:'top',labels:{color:'#666',boxWidth:10,padding:10}}},
      scales:{x:{grid:{color:GC},ticks:{color:'#555'}},y:{grid:{color:GC},ticks:{color:'#555',callback:v=>'€'+v.toFixed(1)}}}}
  });

  // Monthly detail table
  // Build monthly summary from filtered data
  // Build monthly summary from merged hd data
  const hbmMap = {};
  hd.forEach(r => {
    const mName = r.month ? (r.month.charAt(0).toUpperCase() + r.month.slice(1).toLowerCase()) : '';
    const key = r.year + '-' + mName;
    if (!hbmMap[key]) hbmMap[key] = {year:r.year, month:mName, gross:0, net:0, covers:0, days:0};
    hbmMap[key].gross   += r.gross;
    hbmMap[key].net     += r.net;
    hbmMap[key].covers  += r.covers;
    hbmMap[key].days    += 1;
  });
  const hbm = Object.values(hbmMap);
  // For the table, show months relevant to the filter
  const tableMonths = selMonthFull ? [selMonthFull] : MONTHS_L;
  $('hb-page-table').innerHTML=`
    <table style="width:100%;border-collapse:collapse">
      <thead><tr>
        ${['Month','Year','Days','Gross','Net','Margin','Covers','Avg/Cover'].map(h=>`<th style="padding:7px 10px;font-family:monospace;font-size:10px;color:#555;text-transform:uppercase;border-bottom:1px solid rgba(255,255,255,.07);background:#16161f">${h}</th>`).join('')}
      </tr></thead>
      <tbody>
        ${tableMonths.flatMap(m=>yrs.map(y=>{
          const r=hbm.find(x=>x.year==y&&x.month===m);
          if(!r||r.gross===0) return '';
          return `<tr style="border-bottom:1px solid rgba(255,255,255,.03)">
            <td style="padding:7px 10px;font-weight:700">${m.slice(0,3)}</td>
            <td><span style="color:${YEAR_COLORS[y]};font-weight:700">${y}</span></td>
            <td class="mono" style="padding:7px 10px">${r.days}</td>
            <td class="mono" style="padding:7px 10px;color:#f5c842">${fmt(r.gross)}</td>
            <td class="mono" style="padding:7px 10px;color:#f5c842">${fmt(r.net)}</td>
            <td class="mono" style="padding:7px 10px">${r.gross?((r.net/r.gross)*100).toFixed(1)+'%':'—'}</td>
            <td class="mono" style="padding:7px 10px">${fmtN(r.covers)}</td>
            <td class="mono" style="padding:7px 10px;color:#00d4aa">${r.covers?'€'+(r.net/r.covers).toFixed(1):'—'}</td>
          </tr>`;
        })).join('')}
        <tr style="border-top:2px solid rgba(255,255,255,.1);font-weight:700">
          <td colspan="3" style="padding:7px 10px">TOTAL (filtered)</td>
          <td class="mono" style="padding:7px 10px;color:#f5c842">${fmt(tG)}</td>
          <td class="mono" style="padding:7px 10px;color:#f5c842">${fmt(tN)}</td>
          <td class="mono" style="padding:7px 10px">${tG?((tN/tG)*100).toFixed(1)+'%':'—'}</td>
          <td class="mono" style="padding:7px 10px">${fmtN(tC)}</td>
          <td class="mono" style="padding:7px 10px;color:#00d4aa">${tC?'€'+(tN/tC).toFixed(1):'—'}</td>
        </tr>
      </tbody>
    </table>`;
}

// ═══════════════════════════════════════════════════════════════════
