window.addDish = function() {
  const name  = $('me-name')?.value?.trim();
  const cat   = $('me-cat')?.value;
  const price = parseFloat($('me-price')?.value||0);
  const cost  = parseFloat($('me-cost')?.value||0);
  const units = parseInt($('me-units')?.value||0);
  if(!name || !price) { toast('Enter dish name and price','error'); return; }
  const type = MENU_DATA?.find(x=>x.category===cat)?.type || 'Food';
  const dishes = loadMenu();
  dishes.push({name, category:cat, type, price, cost, units});
  saveMenu(dishes);
  renderMenuEngineering();
  toast('Dish added ✓','success');
};


window.removeDish = function(i) {
  const dishes = loadMenu();
  dishes.splice(i,1);
  saveMenu(dishes);
  renderMenuEngineering();
};

